#include <bits/stdc++.h>
using namespace std;
const int mod=1e9+7;
int ans;
string s;
int num[2000006];
int main(){
    cin>>s;
    int n=s.size();
    s=" "+s;
    for(int i=1;i<=n;i++)
        num[i]=(1LL*num[i-1]*10%mod+1)%mod;
    for(int i=1;i<=n;i++)
        ans+=1LL*(s[i]-'0')*i*num[n-i+1]%mod,ans%=mod;
    printf("%d",ans);
    return 0;
}
